  "apply_services_mode" text DEFAULT 'all' NOT NULL CHECK ("apply_services_mode" IN ('none', 'all', 'selected')),
  "apply_products_mode" text DEFAULT 'none' NOT NULL CHECK ("apply_products_mode" IN ('none', 'all', 'selected')),
  "target_type" text DEFAULT 'all' NOT NULL CHECK ("target_type" IN ('all', 'new', 'inactive', 'birthday', 'fidelity')),
  "new_within_days" integer,
  "inactive_days" integer,
  "birthday_window_days" integer,
