  "per_customer_limit" integer,
  "per_day_limit" integer,
  "stackable" integer DEFAULT 0 NOT NULL,
  "stop_processing" smallint DEFAULT 0 NOT NULL,
  "promo_conditions_enabled" smallint DEFAULT 0 NOT NULL,
  "promo_conditions" text,
  "products_discount_type" text CHECK ("products_discount_type" IN ('percent', 'fixed')),
  "products_discount_value" numeric(10,2),
  "products_min_subtotal" numeric(10,2),
  "products_min_qty" integer,
  "products_discounted_qty" integer,
