-- Multi-tenant safety net: fill tenant_id from app.tenant_id GUC on insert
CREATE OR REPLACE FUNCTION app_set_tenant_id() RETURNS trigger AS $$
BEGIN
  IF NEW.tenant_id IS NULL OR NEW.tenant_id = 0 THEN
    NEW.tenant_id := COALESCE(NULLIF(current_setting('app.tenant_id', true), '')::int, 0);
  END IF;
  RETURN NEW;
END; $$ LANGUAGE plpgsql;
