-- ON UPDATE CURRENT_TIMESTAMP replacement triggers
CREATE OR REPLACE FUNCTION "app_touch_updated_at"() RETURNS trigger AS $$
BEGIN NEW."updated_at" := CURRENT_TIMESTAMP; RETURN NEW; END; $$ LANGUAGE plpgsql;
